import { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import { useUserProfile } from '../contexts/UserProfileContext';
import { transformToFinancialProduct } from '../utils/finance';
import ProductCard from '../components/ProductCard';
import './Recommendations.css';

const RISK_COLORS = {
  conservative: 'var(--clr-low)',
  moderate:     'var(--clr-medium)',
  aggressive:   'var(--clr-high)',
};

export default function Recommendations() {
  const { profile, isProfileComplete, computeRecommendations } = useUserProfile();
  const [allProducts, setAll]   = useState([]);
  const [loading, setLoading]   = useState(true);

  useEffect(() => {
    fetch('https://fakestoreapi.com/products')
      .then(r => r.json())
      .then(data => {
        setAll(data.map(transformToFinancialProduct));
        setLoading(false);
      })
      .catch(() => setLoading(false));
  }, []);

  if (!isProfileComplete()) {
    return (
      <div className="page page-enter">
        <div className="container rec-no-profile">
          <div style={{ fontSize: 56, marginBottom: 20 }}>🎯</div>
          <h2>Create Your Profile First</h2>
          <p>We need to know your risk tolerance, investment goals, and budget to recommend products.</p>
          <Link to="/profile" className="btn btn-primary" style={{ marginTop: 20 }}>
            Create Financial Profile →
          </Link>
        </div>
      </div>
    );
  }

  const recommendations = computeRecommendations(allProducts);

  return (
    <div className="page page-enter">
      <div className="container">
        <div className="rec-header">
          <div>
            <h1 className="section-title">Your <span>Recommendations</span></h1>
            <p className="section-subtitle">
              Personalized for your <strong style={{ color: RISK_COLORS[profile.riskTolerance] }}>
                {profile.riskTolerance}
              </strong> profile · {recommendations.length} products matched
            </p>
          </div>
          <Link to="/profile" className="btn btn-outline btn-sm">Edit Profile</Link>
        </div>

        {/* Profile Summary Bar */}
        <div className="rec-profile-bar">
          {[
            { label: 'Risk', val: profile.riskTolerance },
            { label: 'Horizon', val: profile.investmentHorizon },
            { label: 'Budget', val: `PKR ${Number(profile.monthlyCapacity).toLocaleString()}` },
            { label: 'Liquidity', val: profile.liquidityPreference },
            { label: 'Goal', val: profile.investmentGoal },
          ].map(item => (
            <div key={item.label} className="rec-profile-item">
              <span className="rec-profile-label">{item.label}</span>
              <span className="rec-profile-val">{item.val}</span>
            </div>
          ))}
        </div>

        {loading && (
          <div className="loading-wrap"><div className="spinner" /><p>Loading…</p></div>
        )}

        {!loading && recommendations.length === 0 && (
          <div className="empty-state">
            <h3>No products matched your profile</h3>
            <p>Try relaxing your budget or updating your risk tolerance.</p>
            <Link to="/profile" className="btn btn-outline" style={{ marginTop: 16 }}>Update Profile</Link>
          </div>
        )}

        {!loading && recommendations.length > 0 && (
          <div className="products-grid">
            {recommendations.map(p => <ProductCard key={p.id} product={p} />)}
          </div>
        )}
      </div>
    </div>
  );
}
